46	function buildBreadcrumbs(pathname: string): { label: string; href: string }[] {
47	  const segments = pathname.split("/").filter(Boolean);
48	  const crumbs: { label: string; href: string }[] = [];
49	
50	  let href = "";
51	  for (const segment of segments) {
52	    href += "/" + segment;
53	    crumbs.push({
54	      label: breadcrumbLabels[segment] || segment,
55	      href,
56	    });
57	  }
58	
59	  return crumbs;
60	}
