49	
50	  let href = "";
51	  for (const segment of segments) {
52	    href += "/" + segment;
53	    crumbs.push({
54	      label: breadcrumbLabels[segment] || segment,
55	      href,
56	    });
57	  }
58	
59	  return crumbs;
60	}
